class MagixVatCalculator{constructor(e){this.vatRate=(parseFloat(e.toString().replace(",","."))||0)/100}parsePrice(e){let t=parseFloat(e.toString().replace(",","."));return isNaN(t)?0:t}bindFields(e,t){const a=document.getElementById(e),r=document.getElementById(t);if(!a||!r)return void console.warn(`VatCalculator: Impossible de trouver les champs ${e} ou ${t}`);const s=()=>{let e=this.parsePrice(a.value)*(1+this.vatRate);r.value=e>0?e.toFixed(2):"0.00"};a.addEventListener("input",s),r.addEventListener("input",(()=>{let e=this.parsePrice(r.value)/(1+this.vatRate);a.value=e>0?e.toFixed(2):"0.00"})),s()}}